class Solution:
    def countOfPeaks(self, nums: List[int], queries: List[List[int]]) -> List[int]:
        import sys
        input = sys.stdin.read
        sys.setrecursionlimit(1 << 25)

        n = len(nums)
        peak = [0] * n

        for i in range(1, n - 1):
            if nums[i] > nums[i - 1] and nums[i] > nums[i + 1]:
                peak[i] = 1

        class SegmentTree:
            def __init__(self, data):
                self.n = len(data)
                self.size = 1
                while self.size < self.n:
                    self.size <<= 1
                self.tree = [0] * (2 * self.size)
                for i in range(self.n):
                    self.tree[self.size + i] = data[i]
                for i in range(self.size - 1, 0, -1):
                    self.tree[i] = self.tree[2 * i] + self.tree[2 * i + 1]

            def update(self, pos, value):
                pos += self.size
                self.tree[pos] = value
                pos >>= 1
                while pos >= 1:
                    new_val = self.tree[2 * pos] + self.tree[2 * pos + 1]
                    if self.tree[pos] == new_val:
                        break
                    self.tree[pos] = new_val
                    pos >>= 1

            def query(self, l, r):
                res = 0
                l += self.size
                r += self.size
                while l <= r:
                    if l % 2 == 1:
                        res += self.tree[l]
                        l += 1
                    if r % 2 == 0:
                        res += self.tree[r]
                        r -= 1
                    l >>= 1
                    r >>= 1
                return res

        st = SegmentTree(peak)
        result = []

        for q in queries:
            if q[0] == 1:
                l, r = q[1], q[2]
                # Peaks can only be in positions [l+1, r-1]
                if l + 1 > r - 1:
                    result.append(0)
                else:
                    result.append(st.query(l + 1, r - 1))
            else:
                idx, val = q[1], q[2]
                # Check if current index is a peak
                if idx > 0 and idx < n - 1:
                    if nums[idx] > nums[idx - 1] and nums[idx] > nums[idx + 1]:
                        st.update(idx, 1)
                    else:
                        st.update(idx, 0)
                # Update nums
                nums[idx] = val
                # Check neighbors
                for i in [idx - 1, idx + 1]:
                    if 0 <= i < n - 1:
                        if nums[i] > nums[i - 1] and nums[i] > nums[i + 1]:
                            st.update(i, 1)
                        else:
                            st.update(i, 0)

        return result
